const data = $('Fetch Listing Context').first().json;
const faqNode = $('Fetch FAQ and Policies').first().json;
let historyItems = [];
try { historyItems = $('Load Conversation History').all(); } catch(e) {}

const faqContent = faqNode.content || faqNode.faq_content || 'Shop policies not available.';

const historyLines = historyItems
  .filter(item => item.json && item.json['Conversation ID'] === data.conversation_id)
  .slice(-10)
  .map(item => {
    const msg = item.json['Message'] || '';
    const resp = item.json['Draft Response/Our Response'] || '';
    return '[customer] ' + msg + (resp ? '
[agent] ' + resp : '');
  })
  .join('
');

const orders = data.orders || [];
const today = new Date();
const ordersText = orders.map(o => {
  const orderDate = new Date(o.date);
  const daysSince = Math.floor((today - orderDate) / (1000 * 60 * 60 * 24));
  const withinWindow = daysSince <= 30 ? ' [WITHIN 30-DAY WINDOW]' : ' [OUTSIDE 30-DAY WINDOW]';
  const itemsList = o.items.map(i => `${i.qty}x ${i.variant} ${(data.all_listings[i.sku] || {}).title || i.sku} ($${i.price})`).join(', ');
