  const notesStr = o.notes ? ` | Note: ${o.notes}` : '';
  return `${o.order_id} | ${o.customer} | ${o.date}${withinWindow} | Status: ${o.status} | Items: ${itemsList} | Total: $${o.total}${trackingStr}${notesStr}`;
