const response = $input.first().json;
const originalData = $('Build AI Context').first().json;
let classification;
try {
  const rawText = response.content?.[0]?.text || '';
  const cleaned = rawText.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
  classification = JSON.parse(cleaned);
} catch(e) {
  classification = {
    intents: [{ type: 'Unknown', priority: 'HIGH', description: 'Parse error — needs human review', answerable_from_context: false }],
    primary_priority: 'HIGH',
    recommended_action: 'escalate',
    sentiment: 'Neutral',
    risk_level: 'Standard',
    confidence: 0,
    auto_respond_safe: false,
    financial_topic: false,
    reasoning: 'Failed to parse AI response: ' + e.message,
    suggested_response: ''
  };
}

// Clamp recommended_action to valid values
const validActions = ['immediate_alert','batch_review','auto_respond','escalate'];
if (!validActions.includes(classification.recommended_action)) {
  const allLow = classification.intents && classification.intents.every(i => i.priority === 'LOW');
  classification.recommended_action = (allLow && classification.confidence >= 80) ? 'auto_respond' : 'escalate';
}
// HIGH priority always overrides to immediate_alert — never escalate a high-priority message on low confidence
if (classification.primary_priority === 'HIGH') {
  classification.recommended_action = 'immediate_alert';
}
// Sync auto_respond_safe with actual action
if (classification.recommended_action !== 'auto_respond') {
  classification.auto_respond_safe = false;
}
// Hard safety overrides
if (classification.financial_topic || classification.risk_level === 'Revenue' || classification.risk_level === 'Reputational') {
  classification.auto_respond_safe = false;
}
return [{ json: { ...originalData, classification, processed_at: new Date().toISOString() } }];

