    auto_reply_request: {
      model: 'claude-sonnet-4-6',
      max_tokens: 512,
      temperature: 0,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }]
    }
  }
}];

const response = $input.first().json;
const originalData = $('Build Auto-Reply Request').first().json;
